/// <summary>
/// Extension of the <c>PurchAgreementHeader</c> <c>FormDataSource</c> in the <c>PurchAgreementCreate</c> form for the ETGSPAIN model.
/// </summary>
[ExtensionOf(formDataSourceStr(PurchAgreementCreate, PurchAgreementHeader))]
final class PurchAgreementCreatePurchAgreementHeaderETGSPAIN_Extension
{    

}

Method.Source:
/// <summary>
/// Extension of the <c>initValue</c> method.
/// </summary>
public void initValue()
{
    next initValue();        

    FormRun                 formRun                 = this.formRun();
    AgreementFormArgs       purchAgreementFormArgs  = formRun.parmPurchAgreementFormArgs();
    PurchAgreementHeader    purchAgreementHeader    = this.cursor() as PurchAgreementHeader;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        purchAgreementHeader.DefaultAgreementLineExpirationDate = dateMax();

        switch (purchAgreementFormArgs.parmCallerDataSet())
        {
            case tableNum(ETGSPAINPurchOperationTable):

                PurchAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);

                ETGSPAINPurchOperationTable ETGSPAINPurchOperationTable = purchAgreementFormArgs.parmCallerRecord() as ETGSPAINPurchOperationTable;

                purchAgreementHeader.ETGSPAINAgreementOperationId = ETGSPAINPurchOperationTable.OperationId;

                break;
        }
    }
}

/// <summary>
/// Extension of the <c>active</c> method.
/// </summary>
/// <returns>Returns an integer.</returns>
public int active()
{
    int     ret     = next active();
    FormRun formRun = this.formRun();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        PurchAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);
    }

    return ret;
}

/// <summary>
/// <c>EventHandler</c> triggered whenever the <c>PurchAgreementCreate</c> data source is modified.
/// </summary>
/// <param name="_sender">FormDataObject.</param>
/// <param name="_e">FormDataFieldEventArgs.</param>
[FormDataSourceEventHandler(formDataSourceStr(PurchAgreementCreate, PurchAgreementHeader), FormDataSourceEventType::ValidatedWrite)]
public static void PurchAgreementHeader_OnValidatedWrite(FormDataSource _sender, FormDataSourceEventArgs _e)
{       
    FormRun formRun = _sender.formRun();
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        PurchAgreementHeader::ETGSPAINmandatoryOperationFields(formRun);
    }
}
